        "date": "2025-06-17",
        "author": "Token Mallick",
        "imageUrl": "https://blogger.googleusercontent.com/img/b/R29vZ2xl/AVvXsEiCEF5elqdYz2hwYguGi6nrpgOURwBiGP_9bAF5TdGmRhbRsc72IVwR6DZisHnT8TK7xz2JwvgHgKOJCanoAsDRY7T3D4RAEe8qemz0sBmZkFXA40y-Ftf7ZKjpaNtRU6XhHCwM5YW4mnn1jgH0vrcrqFIp_GI_mQBVqV5-8sxDY332Aoj7jbNdS4daRHU6/s800/ChatGPT%20Image%20Jun%2014,%202025,%2012_05_45%20PM.png"
